import 'dart:convert';import 'dart:io';import 'package:http/http.dart' as http;import 'app_config.dart';import 'auth_storage.dart';
class ApiClient{static Uri u(String e,[Map<String,dynamic>?q]){final uri=Uri.parse('${AppConfig.baseUrl}/${e.startsWith('/')?e.substring(1):e}');return q==null?uri:uri.replace(queryParameters:q.map((k,v)=>MapEntry(k,'$v')));}static Future<Map<String,dynamic>> get(String e,{Map<String,dynamic>?query})async{final t=await AuthStorage.token();final r=await http.get(u(e,query),headers:{'Accept':'application/json',if(t!=null)'Authorization':'Bearer $t'});return d(r);}static Future<Map<String,dynamic>> post(String e,{Map<String,dynamic>?body})async{final t=await AuthStorage.token();final r=await http.post(u(e),headers:{'Accept':'application/json','Content-Type':'application/json',if(t!=null)'Authorization':'Bearer $t'},body:jsonEncode(body??{}));return d(r);}static Future<Map<String,dynamic>> multipart(String e,{Map<String,String>?fields,File?file,String fileField='attachment'})async{final t=await AuthStorage.token();final req=http.MultipartRequest('POST',u(e));req.headers['Accept']='application/json';if(t!=null)req.headers['Authorization']='Bearer $t';req.fields.addAll(fields??{});if(file!=null)req.files.add(await http.MultipartFile.fromPath(fileField,file.path));return d(await http.Response.fromStream(await req.send()));}static Map<String,dynamic>d(http.Response r){try{final x=jsonDecode(r.body);return x is Map<String,dynamic>?x:{'status':'error','message':'Response tidak valid','data':x};}catch(_){return {'status':'error','message':'Response server tidak valid: ${r.body}'};}}}
